            ctx.strokeStyle = depth > 4 ? '#5C4033' : '#228B22'; // Brown for trunk, green for leaves
            ctx.stroke();

            // Recursive step: draw two new branches
            // Left branch
            drawBranch(x2, y2, length * lengthReductionFactor, angle - branchAngle, depth - 1);
            // Right branch
            drawBranch(x2, y2, length * lengthReductionFactor, angle + branchAngle, depth - 1);
        }

