        function drawBranch(startX, startY, length, angle, depth, maxDepth) {
            if (depth > maxDepth) {
                return;
            }

            // Calculate end point of the branch
            const endX = startX + length * Math.cos(angle);
            const endY = startY + length * Math.sin(angle);

            // Set line properties based on depth
            ctx.beginPath();
            ctx.moveTo(startX, startY);
            ctx.lineTo(endX, endY);
            ctx.lineWidth = Math.max(1, (maxDepth - depth + 1) * 1.5); // Thicker for lower depth branches
            ctx.strokeStyle = `hsl(120, 50%, ${30 + (depth / maxDepth) * 40}%)`; // Greenish, lighter for higher depth
            ctx.stroke();

            // Recursively draw two new branches
            // Angle adjustments and length scaling for sub-branches
            const newLength = length * 0.75;
            const angleOffset = Math.PI / 6; // 30 degrees

            // Left branch
            drawBranch(endX, endY, newLength, angle - angleOffset, depth + 1, maxDepth);
            // Right branch
            drawBranch(endX, endY, newLength, angle + angleOffset, depth + 1, maxDepth);
        }

        // Function to clear canvas and draw the full tree
        function drawFractalTree() {
            ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT); // Clear the entire canvas

            const maxDepth = parseInt(depthSlider.value);
            depthValueSpan.textContent = maxDepth;

            // Initial branch parameters
            const initialLength = CANVAS_HEIGHT / 4; // Starting length of the trunk
            const startX = CANVAS_WIDTH / 2;
            const startY = CANVAS_HEIGHT; // Start at the bottom center
            const initialAngle = -Math.PI / 2; // Pointing upwards

            // Draw the initial trunk (or the first set of branches directly)
            // We can call drawBranch for the trunk itself, or just directly call for its children.
            // For simplicity and consistency with the recursive definition, we'll draw the "trunk" as the first branch.
            drawBranch(startX, startY, initialLength, initialAngle, 1, maxDepth);
        }

        // Event listener for slider changes
        depthSlider.addEventListener('input', drawFractalTree);

        // Initial draw when the page loads
        drawFractalTree();
    </script>
