        const BRANCH_DECREASE_FACTOR = 0.75; // How much shorter each new branch is
        const ANGLE_CHANGE = Math.PI / 6; // Radians (30 degrees)

        let maxDepth = parseInt(depthSlider.value); // Initial depth from slider

        // Function to draw a single branch
        function drawBranch(x1, y1, x2, y2, depth) {
            ctx.beginPath();
            ctx.moveTo(x1, y1);
            ctx.lineTo(x2, y2);
            // Make branches thinner and lighter with increasing depth
            ctx.lineWidth = Math.max(1, (maxDepth - depth + 1) * 2); 
            ctx.strokeStyle = `hsl(120, 50%, ${30 + (depth / maxDepth) * 30}%)`; // Greenish, lighter with depth
            ctx.stroke();
        }

        // Recursive function to draw the fractal tree
        function drawTree(x1, y1, angle, depth) {
            // Base case: Stop recursion if depth is 0
            if (depth === 0) {
                return;
            }

            // Calculate current branch length based on initial length and depth
            const branchLength = INITIAL_BRANCH_LENGTH * Math.pow(BRANCH_DECREASE_FACTOR, maxDepth - depth);

            // Calculate end point of the current branch
            const x2 = x1 + Math.cos(angle) * branchLength;
            const y2 = y1 + Math.sin(angle) * branchLength;

            // Draw the current branch
            drawBranch(x1, y1, x2, y2, depth);

            // Recursively draw left sub-branch
            // Angle is adjusted to the left (subtract ANGLE_CHANGE)
            // Depth is decreased by 1
            drawTree(x2, y2, angle - ANGLE_CHANGE, depth - 1);

            // Recursively draw right sub-branch
            // Angle is adjusted to the right (add ANGLE_CHANGE)
            // Depth is decreased by 1
            drawTree(x2, y2, angle + ANGLE_CHANGE, depth - 1);
        }

        // Function to clear canvas and redraw the tree
        function redrawCanvas() {
            ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT); // Clear the entire canvas

            // Start drawing the tree from the bottom center, pointing upwards (angle = -Math.PI / 2)
            drawTree(CANVAS_WIDTH / 2, CANVAS_HEIGHT, -Math.PI / 2, maxDepth);
        }

        // --- Event Listener for Slider ---
        depthSlider.addEventListener('input', () => {
            maxDepth = parseInt(depthSlider.value);
            currentDepthSpan.textContent = maxDepth; // Update displayed depth
            redrawCanvas(); // Redraw tree with new depth
        });

        // --- Initial Drawing ---
        // Draw the tree when the page loads
        redrawCanvas();

    </script>
