    <h1>Interactive Fractal Tree & Deep Dive into Recursion Limits</h1>

    <div class="container">
        <div class="canvas-section">
            <h2>Fractal Tree Visualization</h2>
            <div class="controls">
                <label for="depthSlider">Recursion Depth:</label>
